166	        Commands::Init(init_args) => run_command(init::init(&init_args)),
167	        Commands::Symlink(symlink_args) => run_command(symlink::symlink(&symlink_args)),
168	        Commands::Sync(sync_args) => run_command(sync::sync(&sync_args)),
169	        Commands::Finalize(finalize_args) => {
170	            let opts = match finalize_args.into_opts(cli.log) {
171	                Ok(opts) => opts,
172	                Err(e) => {
173	                    error!("{e}");
174	                    return ExitCode::FAILURE;
175	                }
